<script>
import proto from "../assets/sdkapi_pb.js"
export default {
  name: 'ActionWheel',
  props: {
    msg: String
  },
  data() {
    this.chart = null;
    return {
      actionFinished: true,
    };
  },
  mounted() {
    var that = this;
    this.$bus.$on("websocket-data-received", function(d) {
      var data = d.data;
      if (data.command == proto.Command.CMD_RUN_ACTION) {
        that.onActionFinished(data);
      }
    });

    this.$bus.$on("websocket-error", function(data) {
      console.error("websocket-error: ", data);
      that.onActionFinished(data);
    });
  },
  methods: {
    handleSelect(key, keyPath) {
      console.log(key, keyPath);
    },
    onClickAction(action) {
      var request = new proto.Request();
      request.setCommand(proto.Command.CMD_RUN_ACTION);
      var param_data = request.addParamData();
      param_data.setKey("action");
      param_data.setVal(action);
      var d = request.serializeBinary();
      console.log("request run action: action: " + action);
      this.$bus.$emit("websocket-send-data", { data: d });
      this.actionFinished = false;
    },
    onActionFinished(data) {
      if (data.errorCode !== proto.ErrorCode.ERROR_CODE_SUCCESS) {
        console.error("run action error：code: " + this.getErrorCodeAsString(data.errorCode) + ": " + data.errorMessage, data);
        this.actionFinished = true;
        return;
      } else {
        console.log("run action ok：code: " + this.getErrorCodeAsString(data.errorCode));
      }
      this.actionFinished = true;
    },
    getErrorCodeAsString(code) {
      if (code == proto.ErrorCode.ERROR_CODE_SUCCESS) {
        return "ERROR_CODE_SUCCESS";
      } else if (code == proto.ErrorCode.ERROR_CODE_ACTION_NOT_IMPLEMENT) {
        return "ERROR_CODE_ACTION_NOT_IMPLEMENT";
      } else if (code == proto.ErrorCode.ERROR_CODE_ACTION_TIMEOUT) {
        return "ERROR_CODE_ACTION_TIMEOUT";
      } else if (code == proto.ErrorCode.ERROR_CODE_SERVER_STOPPED) {
        return "ERROR_CODE_SERVER_STOPPED";
      } else if (code == proto.ErrorCode.ERROR_CODE_SERVER_INTERNAL_ERROR) {
        return "ERROR_CODE_SERVER_INTERNAL_ERROR";
      } else {
        return code;
      }
    },
  }
}
</script>

